{"command": "cd /tmp/sv-f495e6b588634bb098ea25774d557a9c/symbols

# Check the debuglink 
aarch64-linux-gnu-readelf --string-dump=.gnu_debuglink libmonosgen-2.0.so 2>/dev/null || readelf --string-dump=.gnu_debuglink libmonosgen-2.0.so 2>/dev/null

# Check dynamic symbols - these survive stripping
aarch64-linux-gnu-nm -D --defined-only libmonosgen-2.0.so 2>/dev/null | head -5
echo "Total dynamic symbols: $(aarch64-linux-gnu-nm -D --defined-only libmonosgen-2.0.so 2>/dev/null | wc -l)"

# Use the dynamic symbol table to resolve our addresses
# Frames from libmonosgen-2.0.so: 0x222098, 0x222234, 0x19bac0, 0x19bc14
echo ""
echo "=== Resolving libmonosgen-2.0.so frames ==="
for addr in 0x222098 0x222234 0x19bac0 0x19bc14; do
  # Find the closest symbol at or before this address
  match=$(aarch64-linux-gnu-nm -D --defined-only --numeric-sort libmonosgen-2.0.so 2>/dev/null | awk -v target="$addr" '
    BEGIN { target_dec = strtonum(target) }
    {
      addr_dec = strtonum("0x" $1)
      if (addr_dec <= target_dec) { best_addr = $1; best_sym = $3; best_dec = addr_dec }
      if (addr_dec > target_dec) { printf "%s+0x%x (%s)\n", best_sym, target_dec - best_dec, best_addr; found=1; exit }
    }
    END { if (!found && best_sym) printf "%s+0x%x (%s)\n", best_sym, target_dec - best_dec, best_addr }
  ')
  echo "  pc $addr -> $match"
done", "description": "Resolve symbols from dynamic symbol table"}
